using System.Text;

namespace Starling.Js.Intrinsics;

/// <summary>Unicode normalization (UAX #15) for String.prototype.normalize
/// and localeCompare. The host runs with invariant globalization, where
/// <c>string.Normalize</c> is a no-op, so the engine carries its own tables
/// (generated from the Unicode Character Database 16.0): single-level
/// canonical/compatibility decompositions, nonzero combining classes, and
/// primary composite pairs. Hangul decomposition/composition is algorithmic.</summary>
internal static class StringNormalization
{
    private const int SBase = 0xAC00, LBase = 0x1100, VBase = 0x1161, TBase = 0x11A7;
    private const int LCount = 19, VCount = 21, TCount = 28, NCount = VCount * TCount, SCount = LCount * NCount;

    private static Dictionary<int, int[]>? _canonical;
    private static Dictionary<int, int[]>? _compatibility;
    private static Dictionary<int, byte>? _combiningClass;
    private static Dictionary<long, int>? _pairs;

    internal static string Normalize(string s, bool compatibility, bool compose)
    {
        var ascii = true;
        for (var i = 0; i < s.Length; i++)
        {
            if (s[i] >= 0x80)
            {
                ascii = false;
                break;
            }
        }

        if (ascii)
        {
            return s;
        }

        EnsureTables();
        var cps = Decompose(s, compatibility);
        CanonicalOrder(cps);
        if (compose)
        {
            Compose(cps);
        }

        var sb = new StringBuilder(cps.Count + 8);
        foreach (var cp in cps)
        {
            sb.Append(char.ConvertFromUtf32(cp));
        }

        return sb.ToString();
    }

    private static List<int> Decompose(string s, bool compatibility)
    {
        var outp = new List<int>(s.Length + 8);
        for (var i = 0; i < s.Length; i++)
        {
            var cp = (int)s[i];
            if (char.IsHighSurrogate(s[i]) && i + 1 < s.Length && char.IsLowSurrogate(s[i + 1]))
            {
                cp = char.ConvertToUtf32(s[i], s[i + 1]);
                i++;
            }

            DecomposeCp(cp, compatibility, outp);
        }
        return outp;
    }

    private static void DecomposeCp(int cp, bool compatibility, List<int> outp)
    {
        if (cp >= SBase && cp < SBase + SCount)
        {
            var sIndex = cp - SBase;
            outp.Add(LBase + sIndex / NCount);
            outp.Add(VBase + (sIndex % NCount) / TCount);
            var t = sIndex % TCount;
            if (t != 0)
            {
                outp.Add(TBase + t);
            }

            return;
        }

        if (_canonical!.TryGetValue(cp, out var canon))
        {
            foreach (var c in canon)
            {
                DecomposeCp(c, compatibility, outp);
            }

            return;
        }

        if (compatibility && _compatibility!.TryGetValue(cp, out var compat))
        {
            foreach (var c in compat)
            {
                DecomposeCp(c, compatibility, outp);
            }

            return;
        }

        outp.Add(cp);
    }

    /// <summary>Canonical Ordering Algorithm: stable-sort runs of nonzero
    /// combining classes via adjacent swaps.</summary>
    private static void CanonicalOrder(List<int> cps)
    {
        for (var i = 1; i < cps.Count; i++)
        {
            var cc = CombiningClass(cps[i]);
            if (cc == 0)
            {
                continue;
            }

            var j = i;
            while (j > 0 && CombiningClass(cps[j - 1]) > cc)
            {
                (cps[j - 1], cps[j]) = (cps[j], cps[j - 1]);
                j--;
            }
        }
    }

    /// <summary>Canonical Composition Algorithm over a fully decomposed,
    /// canonically ordered sequence.</summary>
    private static void Compose(List<int> cps)
    {
        if (cps.Count == 0)
        {
            return;
        }

        var result = new List<int>(cps.Count) { cps[0] };
        var starter = CombiningClass(cps[0]) == 0 ? 0 : -1;
        var lastCc = CombiningClass(cps[0]);
        for (var i = 1; i < cps.Count; i++)
        {
            var cp = cps[i];
            var cc = CombiningClass(cp);
            if (starter >= 0 && (lastCc < cc || lastCc == 0))
            {
                var composed = ComposePair(result[starter], cp);
                if (composed >= 0)
                {
                    result[starter] = composed;
                    continue;
                }
            }

            result.Add(cp);
            if (cc == 0)
            {
                starter = result.Count - 1;
            }

            lastCc = cc;
        }
        cps.Clear();
        cps.AddRange(result);
    }

    private static int ComposePair(int a, int b)
    {
        // Hangul: L+V => LV syllable; LV+T => LVT syllable.
        if (a >= LBase && a < LBase + LCount && b >= VBase && b < VBase + VCount)
        {
            return SBase + ((a - LBase) * VCount + (b - VBase)) * TCount;
        }

        if (a >= SBase && a < SBase + SCount && (a - SBase) % TCount == 0 && b > TBase && b < TBase + TCount)
        {
            return a + (b - TBase);
        }

        return _pairs!.TryGetValue(((long)a << 32) | (uint)b, out var composed) ? composed : -1;
    }

    private static int CombiningClass(int cp)
        => cp < 0x0300 ? 0 : (_combiningClass!.TryGetValue(cp, out var cc) ? cc : 0);

    private static void EnsureTables()
    {
        if (_pairs is not null)
        {
            return;
        }

        var canonical = ParseMap(CanonicalData);
        var compatibility = ParseMap(CompatibilityData);
        var ccc = new Dictionary<int, byte>(1024);
        foreach (var entry in CombiningClassData.Split(';'))
        {
            var colon = entry.IndexOf(':');
            ccc[ParseHex(entry, 0, colon)] = (byte)ParseHex(entry, colon + 1, entry.Length);
        }
        var pairs = new Dictionary<long, int>(1024);
        foreach (var entry in PairData.Split(';'))
        {
            var space = entry.IndexOf(' ');
            var colon = entry.IndexOf(':');
            var a = ParseHex(entry, 0, space);
            var b = ParseHex(entry, space + 1, colon);
            pairs[((long)a << 32) | (uint)b] = ParseHex(entry, colon + 1, entry.Length);
        }
        _canonical = canonical;
        _compatibility = compatibility;
        _combiningClass = ccc;
        // Assigned last: the EnsureTables fast check keys off _pairs.
        _pairs = pairs;
    }

    private static Dictionary<int, int[]> ParseMap(string data)
    {
        var map = new Dictionary<int, int[]>(4096);
        foreach (var entry in data.Split(';'))
        {
            var colon = entry.IndexOf(':');
            var cp = ParseHex(entry, 0, colon);
            var rest = entry[(colon + 1)..].Split(' ');
            var vals = new int[rest.Length];
            for (var i = 0; i < rest.Length; i++)
            {
                vals[i] = ParseHex(rest[i], 0, rest[i].Length);
            }

            map[cp] = vals;
        }
        return map;
    }

    private static int ParseHex(string s, int start, int end)
    {
        var v = 0;
        for (var i = start; i < end; i++)
        {
            var c = s[i];
            v = (v << 4) | (c <= '9' ? c - '0' : c - 'a' + 10);
        }
        return v;
    }

